import React, { useState, useEffect } from 'react';
import axios from 'axios';

const Dashboard = () => {
  const [syllabus, setSyllabus] = useState("");
  const [schedule, setSchedule] = useState([]);
  const [loading, setLoading] = useState(false);

  // Load existing schedule from localStorage on mount
  useEffect(() => {
    const savedPlan = localStorage.getItem('studyPulsePlan');
    if (savedPlan) setSchedule(JSON.parse(savedPlan));
  }, []);

  const generateAIPlan = async () => {
    setLoading(true);
    try {
      // Mocking the AI call you'd make to your Gemini/OpenAI backend
      const response = await axios.post('/api/generate-plan', { syllabus });
      const newSchedule = response.data.tasks; // Expecting array of {id, topic, date, completed}
      setSchedule(newSchedule);
      localStorage.setItem('studyPulsePlan', JSON.stringify(newSchedule));
    } catch (err) {
      console.error("Plan generation failed", err);
    }
    setLoading(false);
  };

  const calculateProgress = () => {
    if (schedule.length === 0) return 0;
    const completed = schedule.filter(t => t.completed).length;
    return Math.round((completed / schedule.length) * 100);
  };

  return (
    <div className="p-6 max-w-4xl mx-auto">
      <h1 className="text-2xl font-bold mb-4">StudyPulse Dashboard</h1>
      
      {/* 1. Progress Bar Feature */}
      <div className="w-full bg-gray-200 rounded-full h-4 mb-6">
        <div 
          className="bg-blue-600 h-4 rounded-full transition-all" 
          style={{ width: `${calculateProgress()}%` }}
        ></div>
        <p className="text-sm mt-1">{calculateProgress()}% Syllabus Completed</p>
      </div>

      {/* 2. Syllabus Input Area */}
      {schedule.length === 0 ? (
        <div className="bg-white p-4 shadow rounded">
          <textarea 
            className="w-full border p-2 mb-2"
            placeholder="Paste syllabus topics here (e.g. Differentiation, Integration...)"
            value={syllabus}
            onChange={(e) => setSyllabus(e.target.value)}
          />
          <button 
            onClick={generateAIPlan}
            className="bg-blue-500 text-white px-4 py-2 rounded"
          >
            {loading ? "AI is thinking..." : "Generate My Plan"}
          </button>
        </div>
      ) : (
        /* 3. Day-wise Task Grid Feature */
        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
          {schedule.map((task) => (
            <div key={task.id} className={`p-4 border rounded shadow ${task.completed ? 'bg-green-50' : 'bg-white'}`}>
              <h3 className="font-bold">{task.topic}</h3>
              <p className="text-sm text-gray-500">Scheduled: {task.date}</p>
              <button 
                onClick={() => window.location.href = `/study-room/${task.id}`}
                className="mt-2 text-blue-600 underline"
              >
                {task.completed ? "Review Session" : "Start Session"}
              </button>
            </div>
          ))}
          <button onClick={() => {localStorage.removeItem('studyPulsePlan'); setSchedule([]);}} className="text-red-400 text-sm mt-4">Reset Plan</button>
        </div>
      )}
    </div>
  );
};

export default Dashboard;
